document.querySelectorAll(".tabs").forEach(e=>{let t=e.querySelectorAll(".tabs > .tabs-items > div"),l=e.querySelectorAll(".tabs-link");l.forEach(e=>{e.addEventListener("click",s=>{s.preventDefault();for(let e=0;e<l.length;e++){l[e].classList.remove("active")}e.classList.add("active");let a=e.getAttribute("href").substring(1);const c=document.getElementById(a);for(let e=0;e<t.length;e++){t[e].classList.remove("active")}c.classList.add("active")})})});